`define MacroModuleName FPGA_Target
module Top(
  input logic a,
  input logic b,
  output logic c
);
  `MacroModuleName inst (.a(a), .b(b), .c(c));
endmodule

// FPGA target file
`define MacroModuleName FPGA_Target

// ASIC target file
`define MacroModuleName ASIC_Target

module FPGA_Target(input logic a, output logic b);
  assign b = a;
endmodule
module ASIC_Target(input logic a, output logic b);
  assign b = ~a;
endmodule
